select training_Category,sum(CPD_CPE_Hours_Awarded) over(partition by training_category),sum(cpd_cpe_hours_awarded) from kgsonedatadb.trusted_hist_lnd_glms_kva_details where Dated_On = '2023-09-14T21:30:29.000+0000' and BU <> 'GDC' group by training_Category;

select training_category,(CPD_CPE_Hours_Awarded/sum(CPD_CPE_Hours_Awarded))*100  from (
select training_category,sum(CPD_CPE_Hours_Awarded) as CPD_CPE_Hours_Awarded from kgsonedatadb.trusted_hist_lnd_glms_kva_details where Dated_On = '2023-09-14T21:30:29.000+0000' and BU <> 'GDC' group by training_category) A group by training_category,CPD_CPE_Hours_Awarded;

select Level_Wise,count(1) from kgsonedatadb.test_trusted_hist_lnd_glms_kva_details where file_date > 20220930 group by Level_Wise;

select distinct TrainingCategory from kgsonedatadb.config_hist_dim_training_category